     1→/**
     2→ * Field Editor Component
     3→ * Edit individual form field configuration
     4→ */
     5→
     6→import { useState, useEffect } from 'react';
     7→import type { FormField, FieldType, CalculationSettings, DependentValidation } from '../../types/forms';
     8→import { X } from 'lucide-react';
     9→import { ConditionalRuleEditor } from './ConditionalRuleEditor';
    10→import { CalculationFieldEditor } from './CalculationFieldEditor';
    11→import { DependentValidationEditor } from './DependentValidationEditor';
    12→
    13→interface FieldEditorProps {
    14→  field: FormField | null;
    15→  allFields: FormField[]; // P0: All fields for conditional logic
    16→  onSave: (field: FormField) => void;
    17→  onCancel: () => void;
    18→}
    19→
    20→const FIELD_TYPES: { value: FieldType; label: string }[] = [
    21→  { value: 'text', label: 'Text' },
    22→  { value: 'textarea', label: 'Text Area' },
    23→  { value: 'number', label: 'Number' },
    24→  { value: 'date', label: 'Date' },
    25→  { value: 'time', label: 'Time' },
    26→  { value: 'select', label: 'Select (Dropdown)' },
    27→  { value: 'multiselect', label: 'Multi-Select' },
    28→  { value: 'radio', label: 'Radio Buttons' },
    29→  { value: 'checkbox', label: 'Checkbox' },
    30→  { value: 'rating', label: 'Rating (1-5)' },
    31→  { value: 'scale', label: 'Scale (1-10)' },
    32→  { value: 'file', label: 'File Upload' }, // P0: File upload field type
    33→  { value: 'calculation', label: 'Calculation' }, // P2: Calculated field type
    34→];
    35→
    36→export function FieldEditor({ field, allFields, onSave, onCancel }: FieldEditorProps) {
    37→  const [formData, setFormData] = useState<FormField>(
    38→    field || {
    39→      id: crypto.randomUUID(),
    40→      type: 'text',
    41→      label: '',
    42→      description: '',
    43→      required: false,
    44→      order: 0,
    45→    }
    46→  );
    47→
    48→  const [optionsText, setOptionsText] = useState('');
    49→  const [showAdvancedOptions, setShowAdvancedOptions] = useState(false);
    50→
    51→  useEffect(() => {
    52→    if (field) {
    53→      setFormData(field);
    54→      if (field.options) {
    55→        setOptionsText(field.options.join('\n'));
    56→      }
    57→    }
    58→  }, [field]);
    59→
    60→  const needsOptions = ['select', 'multiselect', 'radio'].includes(formData.type);
    61→
    62→  const handleSubmit = (e: React.FormEvent) => {
    63→    e.preventDefault();
    64→
    65→    if (!formData.label.trim()) {
    66→      alert('Field label is required');
    67→      return;
    68→    }
    69→
    70→    if (needsOptions && !optionsText.trim()) {
    71→      alert('Options are required for this field type');
    72→      return;
    73→    }
    74→
    75→    const finalField: FormField = {
    76→      ...formData,
    77→      options: needsOptions
    78→        ? optionsText.split('\n').filter((opt) => opt.trim()).map((opt) => opt.trim())
    79→        : undefined,
    80→    };
    81→
    82→    onSave(finalField);
    83→  };
    84→
    85→  return (
    86→    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
    87→      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg max-w-2xl w-full max-h-[90vh] overflow-y-auto">
    88→        {/* Header */}
    89→        <div className="flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark sticky top-0 bg-surface-light dark:bg-surface-dark">
    90→          <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
    91→            {field ? 'Edit Field' : 'Add Field'}
    92→          </h2>
    93→          <button
    94→            onClick={onCancel}
    95→            className="p-2 hover:bg-surface-hover-light dark:hover:bg-surface-hover-dark rounded"
    96→            aria-label="Close"
    97→          >
    98→            <X className="w-5 h-5" />
    99→          </button>
   100→        </div>
   101→
   102→        {/* Form */}
   103→        <form onSubmit={handleSubmit} className="p-4 space-y-4">
   104→          {/* Field Type */}
   105→          <div>
   106→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   107→              Field Type *
   108→            </label>
   109→            <select
   110→              value={formData.type}
   111→              onChange={(e) => setFormData({ ...formData, type: e.target.value as FieldType })}
   112→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   113→            >
   114→              {FIELD_TYPES.map((type) => (
   115→                <option key={type.value} value={type.value}>
   116→                  {type.label}
   117→                </option>
   118→              ))}
   119→            </select>
   120→          </div>
   121→
   122→          {/* Label */}
   123→          <div>
   124→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   125→              Label *
   126→            </label>
   127→            <input
   128→              type="text"
   129→              value={formData.label}
   130→              onChange={(e) => setFormData({ ...formData, label: e.target.value })}
   131→              placeholder="e.g., 'How many hours did you sleep?'"
   132→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   133→              required
   134→            />
   135→          </div>
   136→
   137→          {/* Description */}
   138→          <div>
   139→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   140→              Description (Optional)
   141→            </label>
   142→            <textarea
   143→              value={formData.description || ''}
   144→              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
   145→              placeholder="Help text for this field"
   146→              rows={2}
   147→              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   148→            />
   149→          </div>
   150→
   151→          {/* Options (for select/radio/multiselect) */}
   152→          {needsOptions && (
   153→            <div>
   154→              <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   155→                Options (one per line) *
   156→              </label>
   157→              <textarea
   158→                value={optionsText}
   159→                onChange={(e) => setOptionsText(e.target.value)}
   160→                placeholder="Option 1&#10;Option 2&#10;Option 3"
   161→                rows={5}
   162→                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark font-mono text-sm"
   163→                required
   164→              />
   165→            </div>
   166→          )}
   167→
   168→          {/* Validation (for number fields) */}
   169→          {formData.type === 'number' && (
   170→            <div className="grid grid-cols-2 gap-4">
   171→              <div>
   172→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   173→                  Min Value (Optional)
   174→                </label>
   175→                <input
   176→                  type="number"
   177→                  value={formData.validation?.min ?? ''}
   178→                  onChange={(e) =>
   179→                    setFormData({
   180→                      ...formData,
   181→                      validation: {
   182→                        ...formData.validation,
   183→                        min: e.target.value ? Number(e.target.value) : undefined,
   184→                      },
   185→                    })
   186→                  }
   187→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   188→                />
   189→              </div>
   190→              <div>
   191→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   192→                  Max Value (Optional)
   193→                </label>
   194→                <input
   195→                  type="number"
   196→                  value={formData.validation?.max ?? ''}
   197→                  onChange={(e) =>
   198→                    setFormData({
   199→                      ...formData,
   200→                      validation: {
   201→                        ...formData.validation,
   202→                        max: e.target.value ? Number(e.target.value) : undefined,
   203→                      },
   204→                    })
   205→                  }
   206→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   207→                />
   208→              </div>
   209→            </div>
   210→          )}
   211→
   212→          {/* File Upload Configuration */}
   213→          {formData.type === 'file' && (
   214→            <div className="space-y-4 p-4 border border-border-light dark:border-border-dark rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated">
   215→              <h4 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   216→                File Upload Settings
   217→              </h4>
   218→
   219→              {/* Max File Size */}
   220→              <div>
   221→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   222→                  Max File Size (MB)
   223→                </label>
   224→                <input
   225→                  type="number"
   226→                  value={formData.fileConfig?.maxSizeMB ?? 10}
   227→                  onChange={(e) =>
   228→                    setFormData({
   229→                      ...formData,
   230→                      fileConfig: {
   231→                        ...formData.fileConfig,
   232→                        maxSizeMB: Number(e.target.value) || 10,
   233→                        allowedTypes: formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'],
   234→                        multiple: formData.fileConfig?.multiple ?? false,
   235→                      },
   236→                    })
   237→                  }
   238→                  min={1}
   239→                  max={50}
   240→                  className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
   241→                />
   242→              </div>
   243→
   244→              {/* Allowed File Types */}
   245→              <div>
   246→                <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   247→                  Allowed File Types
   248→                </label>
   249→                <div className="space-y-2">
   250→                  {['image/*', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 'text/plain'].map((type) => (
   251→                    <label key={type} className="flex items-center gap-2">
   252→                      <input
   253→                        type="checkbox"
   254→                        checked={formData.fileConfig?.allowedTypes?.includes(type) ?? (type === 'image/*' || type === 'application/pdf')}
   255→                        onChange={(e) => {
   256→                          const currentTypes = formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'];
   257→                          const newTypes = e.target.checked
   258→                            ? [...currentTypes, type]
   259→                            : currentTypes.filter((t) => t !== type);
   260→
   261→                          setFormData({
   262→                            ...formData,
   263→                            fileConfig: {
   264→                              maxSizeMB: formData.fileConfig?.maxSizeMB ?? 10,
   265→                              allowedTypes: newTypes,
   266→                              multiple: formData.fileConfig?.multiple ?? false,
   267→                            },
   268→                          });
   269→                        }}
   270→                        className="w-4 h-4"
   271→                      />
   272→                      <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
   273→                        {type === 'image/*' ? 'Images (PNG, JPG, GIF, etc.)' :
   274→                         type === 'application/pdf' ? 'PDF' :
   275→                         type === 'application/msword' ? 'Word (.doc)' :
   276→                         type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ? 'Word (.docx)' :
   277→                         type === 'text/plain' ? 'Text files' : type}
   278→                      </span>
   279→                    </label>
   280→                  ))}
   281→                </div>
   282→              </div>
   283→
   284→              {/* Multiple Files Toggle */}
   285→              <div className="flex items-center gap-2">
   286→                <input
   287→                  type="checkbox"
   288→                  id="multiple-files"
   289→                  checked={formData.fileConfig?.multiple ?? false}
   290→                  onChange={(e) =>
   291→                    setFormData({
   292→                      ...formData,
   293→                      fileConfig: {
   294→                        maxSizeMB: formData.fileConfig?.maxSizeMB ?? 10,
   295→                        allowedTypes: formData.fileConfig?.allowedTypes || ['image/*', 'application/pdf'],
   296→                        multiple: e.target.checked,
   297→                      },
   298→                    })
