     1→/**
     2→ * Form Renderer Component
     3→ * Renders form fields from template and handles submission
     4→ */
     5→
     6→import { useState, useMemo } from 'react';
     7→import type { FormTemplate, FormValidationResult, ConditionalRule, DependentValidation } from '../../types/forms';
     8→import { evaluateFormula } from '../../utils/formulaEngine';
     9→import {
    10→  TextField,
    11→  TextAreaField,
    12→  NumberField,
    13→  DateField,
    14→  TimeField,
    15→  SelectField,
    16→  MultiSelectField,
    17→  RadioField,
    18→  CheckboxField,
    19→  RatingField,
    20→  ScaleField,
    21→  FileUploadField,
    22→} from './FieldComponents';
    23→
    24→interface FormRendererProps {
    25→  form: FormTemplate;
    26→  onSubmit: (
    27→    answers: Record<string, any>,
    28→    metadata?: { isSpam?: boolean; submissionTimeSeconds?: number }
    29→  ) => void;
    30→  initialValues?: Record<string, any>;
    31→}
    32→
    33→export function FormRenderer({ form, onSubmit, initialValues = {} }: FormRendererProps) {
    34→  const [answers, setAnswers] = useState<Record<string, any>>(initialValues);
    35→  const [errors, setErrors] = useState<Record<string, string>>({});
    36→  const [formLoadTime] = useState(Date.now()); // Track when form was loaded
    37→  const [honeypot, setHoneypot] = useState(''); // Honeypot field value
    38→
    39→  /**
    40→   * Calculate values for calculated fields
    41→   * Returns a map of calculated field IDs to their computed values
    42→   */
    43→  const calculatedValues = useMemo(() => {
    44→    const calculated: Record<string, any> = {};
    45→
    46→    form.fields.forEach((field) => {
    47→      if (field.type === 'calculation' && field.calculationSettings) {
    48→        const { formula, decimalPlaces } = field.calculationSettings;
    49→
    50→        // Evaluate formula using current field values
    51→        const result = evaluateFormula(formula, answers);
    52→
    53→        if (!result.error && result.value !== null && result.value !== undefined) {
    54→          // Format number values based on decimal places
    55→          if (typeof result.value === 'number' && decimalPlaces !== undefined) {
    56→            calculated[field.id] = result.value % 1 === 0
    57→              ? result.value
    58→              : Number(result.value.toFixed(decimalPlaces));
    59→          } else {
    60→            calculated[field.id] = result.value;
    61→          }
    62→        }
    63→      }
    64→    });
    65→
    66→    return calculated;
    67→  }, [form.fields, answers]);
    68→
    69→  /**
    70→   * Evaluate conditional rules to determine which fields should be visible
    71→   * Returns a Set of field IDs that should be shown
    72→   */
    73→  const visibleFieldIds = useMemo(() => {
    74→    const visible = new Set<string>();
    75→
    76→    // Merge answers with calculated values for conditional evaluation
    77→    const allValues = { ...answers, ...calculatedValues };
    78→
    79→    form.fields.forEach((field) => {
    80→      // If no conditional rules, field is always visible
    81→      if (!field.conditionalRules || field.conditionalRules.length === 0) {
    82→        visible.add(field.id);
    83→        return;
    84→      }
    85→
    86→      // Evaluate all rules - field is shown if ANY rule evaluates to 'show' (OR logic)
    87→      const shouldShow = field.conditionalRules.some((rule) =>
    88→        evaluateConditionalRule(rule, allValues)
    89→      );
    90→
    91→      if (shouldShow) {
    92→        visible.add(field.id);
    93→      }
    94→    });
    95→
    96→    return visible;
    97→  }, [form.fields, answers, calculatedValues]);
    98→
    99→  /**
   100→   * Calculate form completion progress
   101→   * Only counts visible fields (respects conditional logic)
   102→   */
   103→  const progress = useMemo(() => {
   104→    if (!form.settings.showProgressBar) return 0;
   105→
   106→    const visibleFields = form.fields.filter((f) => visibleFieldIds.has(f.id));
   107→    if (visibleFields.length === 0) return 0;
   108→
   109→    const answeredFields = visibleFields.filter((field) => {
   110→      const answer = answers[field.id];
   111→
   112→      // Check if field has a valid answer
   113→      if (answer === undefined || answer === null || answer === '') return false;
   114→      if (Array.isArray(answer) && answer.length === 0) return false;
   115→
   116→      return true;
   117→    });
   118→
   119→    return Math.round((answeredFields.length / visibleFields.length) * 100);
   120→  }, [form.fields, form.settings.showProgressBar, visibleFieldIds, answers]);
   121→
   122→  const handleFieldChange = (fieldId: string, value: any) => {
   123→    setAnswers({ ...answers, [fieldId]: value });
   124→    // Clear error when user starts typing
   125→    if (errors[fieldId]) {
   126→      setErrors({ ...errors, [fieldId]: '' });
   127→    }
   128→  };
   129→
   130→  const validateForm = (): FormValidationResult => {
   131→    const newErrors: Record<string, string> = {};
   132→
   133→    // Merge answers with calculated values for validation
   134→    const allValues = { ...answers, ...calculatedValues };
   135→
   136→    form.fields.forEach((field) => {
   137→      // Skip validation for hidden fields (conditional logic)
   138→      if (!visibleFieldIds.has(field.id)) {
   139→        return;
   140→      }
   141→
   142→      // Skip validation for calculated fields (they are read-only)
   143→      if (field.type === 'calculation') {
   144→        return;
   145→      }
   146→
   147→      const value = answers[field.id];
   148→
   149→      // Required validation
   150→      if (field.required) {
   151→        if (value === undefined || value === null || value === '') {
   152→          newErrors[field.id] = 'This field is required';
   153→        } else if (Array.isArray(value) && value.length === 0) {
   154→          newErrors[field.id] = 'Please select at least one option';
   155→        }
   156→      }
   157→
   158→      // Number validation
   159→      if (field.type === 'number' && value !== null && value !== undefined && value !== '') {
   160→        if (field.validation?.min !== undefined && Number(value) < field.validation.min) {
   161→          newErrors[field.id] = `Minimum value is ${field.validation.min}`;
   162→        }
   163→        if (field.validation?.max !== undefined && Number(value) > field.validation.max) {
   164→          newErrors[field.id] = `Maximum value is ${field.validation.max}`;
   165→        }
   166→      }
   167→
   168→      // Dependent validation
   169→      if (field.dependentValidation && field.dependentValidation.length > 0) {
   170→        for (const validation of field.dependentValidation) {
   171→          const error = evaluateDependentValidation(validation, value, allValues);
   172→          if (error) {
   173→            newErrors[field.id] = error;
   174→            break; // Stop at first error
   175→          }
   176→        }
   177→      }
   178→    });
   179→
   180→    return {
   181→      isValid: Object.keys(newErrors).length === 0,
   182→      errors: newErrors,
   183→    };
   184→  };
   185→
