   207→      submissionTimeSeconds = (Date.now() - formLoadTime) / 1000;
   208→
   209→      // Honeypot check: if honeypot field has value, it's spam
   210→      if (honeypot !== '') {
   211→        isSpam = true;
   212→      }
   213→
   214→      // Timing check: submissions faster than 2 seconds are suspicious
   215→      if (submissionTimeSeconds < 2) {
   216→        isSpam = true;
   217→      }
   218→    }
   219→
   220→    // Pass answers and spam metadata
   221→    onSubmit(answers, { isSpam, submissionTimeSeconds });
   222→  };
   223→
   224→  // Sort fields by order
   225→  const sortedFields = [...form.fields].sort((a, b) => a.order - b.order);
   226→
   227→  return (
   228→    <form onSubmit={handleSubmit} className="space-y-6">
   229→      {/* Progress Bar */}
   230→      {form.settings.showProgressBar && (
   231→        <div className="sticky top-0 z-10 bg-background-light dark:bg-background-dark pb-4 -mt-2">
   232→          <div className="flex items-center gap-3">
   233→            <div className="flex-1 h-2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-full overflow-hidden">
   234→              <div
   235→                className="h-full bg-gradient-to-r from-accent-magenta to-accent-cyan transition-all duration-300 ease-out"
   236→                style={{ width: `${progress}%` }}
   237→              />
   238→            </div>
   239→            <span className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary min-w-[4ch]">
   240→              {progress}%
   241→            </span>
   242→          </div>
