   345→      <div className="flex justify-end pt-4">
   346→        <button
   347→          type="submit"
   348→          className="px-6 py-3 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90 transition-opacity font-medium"
   349→        >
   350→          Submit
   351→        </button>
   352→      </div>
   353→    </form>
   354→  );
   355→}
   356→
   357→/**
   358→ * Evaluate a single conditional rule
   359→ * Returns true if the rule evaluates to "show", false if "hide" or condition not met
   360→ */
   361→function evaluateConditionalRule(
   362→  rule: ConditionalRule,
   363→  answers: Record<string, any>
   364→): boolean {
   365→  const triggerValue = answers[rule.fieldId];
   366→
   367→  // Evaluate the condition based on operator
   368→  let conditionMet = false;
   369→
   370→  switch (rule.operator) {
   371→    case 'is_answered':
   372→      conditionMet = triggerValue !== undefined && triggerValue !== null && triggerValue !== '';
   373→      break;
   374→
   375→    case 'is_not_answered':
   376→      conditionMet = triggerValue === undefined || triggerValue === null || triggerValue === '';
   377→      break;
   378→
   379→    case 'equals':
   380→      // Handle array values (multiselect)
   381→      if (Array.isArray(triggerValue)) {
   382→        conditionMet = triggerValue.includes(rule.value);
   383→      } else {
   384→        conditionMet = String(triggerValue) === String(rule.value);
   385→      }
   386→      break;
   387→
   388→    case 'not_equals':
   389→      // Handle array values (multiselect)
   390→      if (Array.isArray(triggerValue)) {
   391→        conditionMet = !triggerValue.includes(rule.value);
   392→      } else {
   393→        conditionMet = String(triggerValue) !== String(rule.value);
   394→      }
   395→      break;
   396→
   397→    case 'contains':
   398→      if (typeof triggerValue === 'string') {
   399→        conditionMet = triggerValue.toLowerCase().includes(String(rule.value).toLowerCase());
   400→      } else if (Array.isArray(triggerValue)) {
   401→        conditionMet = triggerValue.some((v) =>
   402→          String(v).toLowerCase().includes(String(rule.value).toLowerCase())
   403→        );
   404→      }
   405→      break;
   406→
   407→    case 'greater_than':
   408→      conditionMet = Number(triggerValue) > Number(rule.value);
   409→      break;
   410→
   411→    case 'less_than':
   412→      conditionMet = Number(triggerValue) < Number(rule.value);
   413→      break;
   414→
   415→    default:
   416→      conditionMet = false;
   417→  }
   418→
   419→  // Return based on action (show or hide)
   420→  // If action is 'show' and condition is met → return true (show the field)
   421→  // If action is 'hide' and condition is met → return false (hide the field)
   422→  // If action is 'show' and condition is NOT met → return false (don't show)
   423→  // If action is 'hide' and condition is NOT met → return true (don't hide)
   424→  return rule.action === 'show' ? conditionMet : !conditionMet;
   425→}
   426→
   427→/**
   428→ * Evaluate dependent validation rules for a field
   429→ * Returns error message if validation fails, undefined otherwise
   430→ */
   431→function evaluateDependentValidation(
   432→  validation: DependentValidation,
   433→  fieldValue: any,
   434→  answers: Record<string, any>
   435→): string | undefined {
   436→  // First check if the condition is met
   437→  const conditionMet = evaluateConditionalRule(validation.condition, answers);
   438→
   439→  // If condition is not met, skip this validation
   440→  if (!conditionMet) {
   441→    return undefined;
   442→  }
   443→
   444→  // Condition is met, apply validation
   445→  switch (validation.type) {
   446→    case 'require_if':
   447→      if (fieldValue === undefined || fieldValue === null || fieldValue === '') {
   448→        return validation.validationRule.message;
   449→      }
   450→      if (Array.isArray(fieldValue) && fieldValue.length === 0) {
   451→        return validation.validationRule.message;
   452→      }
   453→      break;
   454→
   455→    case 'min_if':
   456→      if (Number(fieldValue) < Number(validation.validationRule.value)) {
   457→        return validation.validationRule.message;
   458→      }
   459→      break;
   460→
   461→    case 'max_if':
   462→      if (Number(fieldValue) > Number(validation.validationRule.value)) {
   463→        return validation.validationRule.message;
   464→      }
   465→      break;
   466→
   467→    case 'pattern_if':
   468→      if (validation.validationRule.value && typeof fieldValue === 'string') {
   469→        const regex = new RegExp(validation.validationRule.value);
   470→        if (!regex.test(fieldValue)) {
   471→          return validation.validationRule.message;
   472→        }
   473→      }
   474→      break;
   475→  }
   476→
   477→  return undefined;
   478→}
